// Complete the isValid function below.
function isValid(s) {
  const sArr = s.split('')
  const map = {}
  // eslint-disable-next-line
  for(let i in sArr) {
    const mapIdx = sArr[i]
    const exists = !!map[mapIdx]
    if (!exists) {
      map[mapIdx] = 1
    } else {
      map[mapIdx] = map[mapIdx] + 1
    }
  }
  let isValid = 'YES'
  // eslint-disable-next-line
  const values = Object.values(map)
  const min = Math.min.apply(null, values)
  const max = Math.max.apply(null, values)
  console.log(min, max, map)
  const diff = max - min
  const numberOfMax = values.filter((i) => i === max)
  const isDiffGreaterThan1 = diff > 1
  const isMaxMoreThanOnce = numberOfMax.length > 1
  if (isDiffGreaterThan1 || isMaxMoreThanOnce) {
    isValid = 'NO'
  }
  // console.log(min, max)
  // for (const i in map) {
  //   if (prevVal) {
  //     const currentVal = map[i]
  //     const diff = currentVal - prevVal
  //     console.log(diff)
  //     if (
  //       !(diff > 1 &&
  //       diff < -1)
  //     ) {
  //       isValid = 'NO'
  //     }
  //   }
  //   prevVal = map[i]
  // }
  return isValid
}
